postToolUse.powershell:
$inputText = [Console]::In.ReadToEnd()
$logName = if ($env:VSTACK_HOOK_LOG_NAME) { $env:VSTACK_HOOK_LOG_NAME } else { 'hook-security-alerts.log' }
$logRoot = if ($env:VSTACK_HOOK_LOG_DIR) { $env:VSTACK_HOOK_LOG_DIR } else { '.vstack/logs' }
$logDir = Join-Path $logRoot (Get-Date).ToUniversalTime().ToString('yyyyMMdd')
New-Item -ItemType Directory -Force -Path $logDir | Out-Null
$logPath = Join-Path $logDir $logName
if ($inputText -notmatch 'git (commit|push|merge|rebase)') {
  exit 0
}
if ((git rev-parse --git-dir 2>$null) -and (git diff --cached | Select-String -Pattern 'AKIA[0-9A-Z]{16}|ghp_[A-Za-z0-9]{36,}|-----BEGIN (RSA|EC|OPENSSH) PRIVATE KEY-----' -Quiet)) {
   Add-Content -Path $logPath -Value 'possible-secrets-detected-in-staged-diff'
}
$mode = if ($env:VSTACK_HOOKS_MODE) { $env:VSTACK_HOOKS_MODE } else { 'audit' }
if ($mode -eq 'enforce') {
  if (Get-Command gitleaks -ErrorAction SilentlyContinue) {
    gitleaks dir . --no-banner --redact *> $null
    if ($LASTEXITCODE -ne 0) {
      Add-Content -Path $logPath -Value 'gitleaks-reported-findings'
    }
  } else {
    Add-Content -Path $logPath -Value 'gitleaks-not-installed'
  }
}
